# Query type resolvers
query = QueryType()

@query.field("user")
def resolve_user(obj: Any, info: Any, id: str) -> Optional[dict]:
    for user in users_db:
        if user["id"] == id:
            return user
    return None

@query.field("users")
def resolve_users(obj: Any, info: Any) -> list:
    return users_db

@query.field("post")
def resolve_post(obj: Any, info: Any, id: str) -> Optional[dict]:
    for post in posts_db:
        if post["id"] == id:
            return post
    return None

@query.field("posts")
def resolve_posts(obj: Any, info: Any) -> list:
    return posts_db

# User type resolvers
user_type = ObjectType("User")

@user_type.field("posts")
def resolve_user_posts(user: dict, info: Any) -> list:
    return [post for post in posts_db if post["authorId"] == user["id"]]

# Post type resolvers
post_type = ObjectType("Post")

@post_type.field("author")
def resolve_post_author(post: dict, info: Any) -> Optional[dict]:
    for user in users_db:
        if user["id"] == post["authorId"]:
            return user
    return None

# Create executable schema
schema = make_executable_schema(type_defs, query, user_type, post_type)

# Simple middleware to simulate authentication
class AuthMiddleware:
    def __init__(self, app):
        self.app = app
    
    async def __call__(self, scope, receive, send):
        if scope["type"] == "http":
            headers = dict(scope.get("headers", []))
            auth_header = headers.get(b"authorization", b"").decode()
            
            # Simple auth simulation - extract user_id from header
            current_user = None
            if auth_header.startswith("Bearer "):
                user_id = auth_header[7:]
                for user in users_db:
                    if user["id"] == user_id:
                        current_user = user
                        break
            
            scope["current_user"] = current_user
        
        await self.app(scope, receive, send)

# Create ASGI application
app = GraphQL(schema, debug=True)
app = AuthMiddleware(app)

